CREATE TYPE "TaskStatus" AS ENUM ('TODO','IN_PROGRESS','BLOCKED','IN_REVIEW','DONE','CANCELLED');
CREATE TABLE "Task"("id" UUID NOT NULL,"organizationId" UUID NOT NULL,"title" TEXT NOT NULL,"description" TEXT,"projectId" UUID,"customerId" UUID,"relatedEntityType" TEXT,"relatedEntityId" UUID,"departmentId" UUID,"priority" "WorkPriority" NOT NULL DEFAULT 'NORMAL',"status" "TaskStatus" NOT NULL DEFAULT 'TODO',"startDate" TIMESTAMP(3),"dueDate" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"createdBy" UUID NOT NULL,"updatedBy" UUID NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"deletedAt" TIMESTAMP(3),"version" INTEGER NOT NULL DEFAULT 1,CONSTRAINT "Task_pkey" PRIMARY KEY("id"));
CREATE TABLE "TaskAssignee"("id" UUID NOT NULL,"organizationId" UUID NOT NULL,"taskId" UUID NOT NULL,"userId" UUID NOT NULL,"assignedBy" UUID NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "TaskAssignee_pkey" PRIMARY KEY("id"));
CREATE TABLE "TaskWatcher"("id" UUID NOT NULL,"organizationId" UUID NOT NULL,"taskId" UUID NOT NULL,"userId" UUID NOT NULL,"createdBy" UUID NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "TaskWatcher_pkey" PRIMARY KEY("id"));
CREATE TABLE "ChecklistItem"("id" UUID NOT NULL,"taskId" UUID NOT NULL,"title" TEXT NOT NULL,"completedAt" TIMESTAMP(3),"completedBy" UUID,"position" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ChecklistItem_pkey" PRIMARY KEY("id"));
CREATE TABLE "TaskDependency"("taskId" UUID NOT NULL,"requiredTaskId" UUID NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "TaskDependency_pkey" PRIMARY KEY("taskId","requiredTaskId"));
CREATE INDEX "Task_organizationId_status_dueDate_deletedAt_idx" ON "Task"("organizationId","status","dueDate","deletedAt");
CREATE INDEX "Task_organizationId_projectId_idx" ON "Task"("organizationId","projectId");
CREATE INDEX "Task_organizationId_departmentId_idx" ON "Task"("organizationId","departmentId");
CREATE INDEX "TaskAssignee_organizationId_userId_idx" ON "TaskAssignee"("organizationId","userId");CREATE UNIQUE INDEX "TaskAssignee_taskId_userId_key" ON "TaskAssignee"("taskId","userId");
CREATE INDEX "TaskWatcher_organizationId_userId_idx" ON "TaskWatcher"("organizationId","userId");CREATE UNIQUE INDEX "TaskWatcher_taskId_userId_key" ON "TaskWatcher"("taskId","userId");CREATE INDEX "ChecklistItem_taskId_position_idx" ON "ChecklistItem"("taskId","position");
